const { Manifold, label, setCircularSegments } = api;
setCircularSegments(48);

function box(min, max) {
  const s = [max[0] - min[0], max[1] - min[1], max[2] - min[2]];
  const c = [(min[0] + max[0]) / 2, (min[1] + max[1]) / 2, (min[2] + max[2]) / 2];
  return Manifold.cube(s, true).translate(c);
}

// Rock base (gray)
const rockBase = label(Manifold.cylinder(3.5, 12, 12, 48), 'rockBase');

// Tapered tower built as a STACK of labeled frustum segments so each
// horizontal band is its own color (a single cylinder's side triangles
// span the full height, which defeats slab-banding).
const zBase = 2.5,
  zTop = 29.5,
  H = zTop - zBase;
const N = 8,
  bandH = H / N;
const rAt = (z) => 8 + (5.5 - 8) * ((z - zBase) / H);
let tower = null;
for (let i = 0; i < N; i++) {
  const lo = (i === 0 ? zBase - 0.6 : zBase + i * bandH - 0.3);
  const hi = zBase + (i + 1) * bandH + 0.3;
  const seg = Manifold.cylinder(hi - lo, rAt(lo), rAt(hi), 48).translate([0, 0, lo]);
  const band = label(seg, i % 2 === 0 ? 'bandRed' : 'bandWhite');
  tower = tower === null ? band : tower.add(band);
}

// Gallery ring around the tower top
const gallery = label(Manifold.cylinder(2, 7, 7, 48).translate([0, 0, 28.5]), 'gallery');

// Glass lamp room
const lampRoom = label(Manifold.cylinder(7, 4.2, 4.2, 48).translate([0, 0, 29]), 'lampRoom');

// Black dome cap (upper half of a sphere)
const domeSphere = Manifold.sphere(4.8, 48).translate([0, 0, 34.5]);
const dome = label(domeSphere.subtract(box([-6, -6, -2], [6, 6, 34.5])), 'dome');

return rockBase.add(tower).add(gallery).add(lampRoom).add(dome);
